sql_query:
SELECT "Control arm"
FROM clinical_trials
WHERE "Cancer type" = 'Multiple Myeloma' AND "Trial phase" = 'Phase 3';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Control arm" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Multiple Myeloma' AND "Trial phase" = 'Phase 3'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_control_category(source_value) AS "control_category"
FROM base;
